  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Caymans Tokenisierte Fonds — Registrierungsverlauf, AUM-Vergleich und das Skalierungsproblem</text>
  <g font-family="sans-serif">
    <rect x="30" y="55" width="640" height="140" rx="10" fill="#1c1c1e" stroke="#71717a" stroke-width="1.2"/>
